// Get both merged items
const items = $input.all();

// AI response is FIRST item
const aiItem = items[0].json;

// Post data is SECOND item
const postItem = items[1].json;

// Parse AI JSON safely
let aiResult;
try {
  const aiText = aiItem.output?.[0]?.content?.[0]?.text;
  aiResult = JSON.parse(aiText);
} catch (e) {
  aiResult = {
    violation: false,
    category: "safe",
    severity: "low",
    reason: "AI response parsing failed"
  };
}

// Merge AI + Post data
return [
  {
    postId: postItem.post_id,
    message: postItem.message,
    userId: postItem.user_id,
    userName: postItem.user_name,
    createdTime: postItem.created_time,

    violation: aiResult.violation,
    category: aiResult.category,
    severity: aiResult.severity,
    reason: aiResult.reason
  }
];

